    int time_base;
};

struct CafContext {
    int64_t num_bytes;
    int packets;
    int packet_cnt;
    int frame_cnt;
    int bytes_per_packet;
    int frames_per_packet;
    double bit_rate;
};

int64_t avio_tell(AVIOContext *s);
int64_t avio_rl32(AVIOContext *s);
int avio_feof(AVIOContext *s);
void avio_skip(AVIOContext *s, int64_t offset);
